VALUES
  ('heelevel3-7fec267e-moex-00253', 'heelevel3-7fec267e', 'heelevel3-7fec267e-moex-111-3082b5f1', 'sub-heelevel3-7fec267e-04', NULL, 'single_choice', '依行政程序法規定，授予利益行政處分之廢止，下列敘述何者正確？', '["廢止，應自廢止原因發生後3年內為之", "行政處分經廢止後，溯及既往失其效力", "行政處分得由原處分機關依職權為全部或一部之廢止", "行政處分之廢止，於補償受益人財產上之損失後始生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:38+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般行政"}'::jsonb, NULL),
  ('heelevel3-7fec267e-moex-00254', 'heelevel3-7fec267e', 'heelevel3-7fec267e-moex-111-3082b5f1', 'sub-heelevel3-7fec267e-04', NULL, 'single_choice', '下列何者非屬行政契約關係？', '["行政機關與醫事服務機構締結提供全民健康保險醫療服務契約", "公立學校聘任教師之契約關係", "學生與教育部指定之銀行締結就學貸款契約", "主管機關與志願役士兵約定最少服役年限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:38+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般行政"}'::jsonb, NULL),
  ('heelevel3-7fec267e-moex-00255', 'heelevel3-7fec267e', 'heelevel3-7fec267e-moex-111-3082b5f1', 'sub-heelevel3-7fec267e-04', NULL, 'single_choice', '依實務見解，關於公法上金錢給付義務人死亡後之行政執行，下列敘述何者正確？', '["納稅義務人死亡後，其納稅能力消滅，無須再予以徵繳", "行政機關課以義務人履行公法上義務之怠金，具有一身專屬性，不得由繼承人繼承", "罰鍰義務人死亡後，仍得就其遺產，進行行政執行", "行政法院依法律規定，就公法上金錢給付義務，僅得依民事執行程序，為假扣押、假處分之裁定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:38+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般行政"}'::jsonb, NULL),
  ('heelevel3-7fec267e-moex-00256', 'heelevel3-7fec267e', 'heelevel3-7fec267e-moex-111-3082b5f1', 'sub-heelevel3-7fec267e-04', NULL, 'single_choice', '關於行政罰之敘述，下列何者錯誤？', '["甲飲酒駕駛汽車，為警攔查，發現其吐氣酒精濃度超過規定標準，經裁罰新臺幣10萬元；而涉 刑事犯罪部分，另經法院判處罰金新臺幣3萬元，基於從輕原則，監理機關依法不可事後再裁 決命甲補繳納新臺幣7萬元", "行政罰之裁處權時效，因天災、事變或依法律規定不能開始或進行裁處時，應停止其進行", "乙同一行為違反同一行政法上義務，A、B機關均有管轄權，因A機關處理在先，因此依法應 由A機關管轄該案件", "行政機關執行行政罰職務之人員，應向違反行政法規定之行為人出示其執行職務之證明文件， 並告知其所違反之法規"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:38+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般行政"}'::jsonb, NULL),
  ('heelevel3-7fec267e-moex-00257', 'heelevel3-7fec267e', 'heelevel3-7fec267e-moex-111-3082b5f1', 'sub-heelevel3-7fec267e-04', NULL, 'single_choice', '行政執行法有關行政執行即時強制之規定，下列敘述何者錯誤？', '["對於執行機關所為損失補償之決定不服者，得依法提起國家賠償", "軍器、凶器及其他危險物，為預防危害之必要，得扣留之", "對於住宅、建築物或其他處所之進入，以人民之生命、身體、財產有迫切之危害，非進入不能 救護者為限", "人民因執行機關依法實施即時強制，致其生命、身體或財產遭受特別損失時，得請求補償 31350、31450 32050、32750 32850 33550"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:38+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般行政"}'::jsonb, NULL),
  ('heelevel3-7fec267e-moex-00258', 'heelevel3-7fec267e', 'heelevel3-7fec267e-moex-111-3082b5f1', 'sub-heelevel3-7fec267e-04', NULL, 'single_choice', '有關政府資訊公開法之敘述，下列何者錯誤？', '["合議制機關之會議紀錄，原則上應主動公開", "政府機關提供政府資訊時，得向申請人收取費用", "政府機關作成意思決定前，內部單位之擬稿原則上不公開或提供", "申請人對於政府機關就其申請提供政府資訊所為之決定不服者，不得提起行政救濟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:38+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般行政"}'::jsonb, NULL),
  ('heelevel3-7fec267e-moex-00259', 'heelevel3-7fec267e', 'heelevel3-7fec267e-moex-111-3082b5f1', 'sub-heelevel3-7fec267e-04', NULL, 'single_choice', '依訴願法規定，下列何者得提起撤銷訴願？', '["請求確認法規命令無效遭拒絕", "對已執行拆除完畢之建物拆除處分", "對已繳納執行完畢之罰鍰處分", "申請公務員迴避遭行政機關駁回"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:38+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般行政"}'::jsonb, NULL),
  ('heelevel3-7fec267e-moex-00260', 'heelevel3-7fec267e', 'heelevel3-7fec267e-moex-111-3082b5f1', 'sub-heelevel3-7fec267e-04', NULL, 'single_choice', '關於訴願決定之敘述，下列何者錯誤？', '["訴願決定確定後，就該事件，有拘束原處分機關之效力", "訴願決定確定後，就受委託行使公權力之事件，受委託行使公權力之團體或個人受其拘束", "原行政處分經撤銷後，原行政處分機關須重為處分者，應依訴願決定意旨為之，並將處理情形 以書面告知受理訴願機關", "內政部之行政處分，經行政院訴願決定撤銷，內政部為確認其處分是否合法，得向行政法院提 起行政訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:38+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般行政"}'::jsonb, NULL),
  ('heelevel3-7fec267e-moex-00261', 'heelevel3-7fec267e', 'heelevel3-7fec267e-moex-111-3082b5f1', 'sub-heelevel3-7fec267e-04', NULL, 'single_choice', '關於行政訴訟法上停止執行制度之敘述，下列何者錯誤？', '["行政法院認原處分之執行，將發生難以回復之損害，且有急迫情事者，得裁定停止執行", "訴訟繫屬中行政處分以不停止執行為原則", "行政法院裁定停止執行前，原處分機關已依職權停止執行者，應為駁回聲請之裁定", "於行政訴訟起訴前，行政法院不得依聲請裁定停止執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:38+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般行政"}'::jsonb, NULL),
  ('heelevel3-7fec267e-moex-00262', 'heelevel3-7fec267e', 'heelevel3-7fec267e-moex-111-3082b5f1', 'sub-heelevel3-7fec267e-04', NULL, 'single_choice', '關於我國行政訴訟制度之訴訟案件管轄，下列敘述何者錯誤？', '["因不動產徵收、徵用或撥用之訴訟，專屬不動產所在地之行政法院管轄", "重新審理之聲請專屬最高行政法院管轄", "交通裁決事件原則上以高等行政法院為終審法院", "定行政法院之管轄以起訴時為準"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:38+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般行政"}'::jsonb, NULL)
